    id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    name VARCHAR(100) NOT NULL,
    enabled BOOLEAN NOT NULL DEFAULT TRUE,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
);

ALTER TABLE measurements
ADD CONSTRAINT ck_measurement_unit
CHECK (unit IN ('V', 'A', 'Ohm', 'Hz'));

ALTER TABLE devices ADD COLUMN location VARCHAR(100);
UPDATE devices SET location = 'unknown' WHERE location IS NULL;
ALTER TABLE devices ALTER COLUMN location SET NOT NULL;

SELECT DISTINCT unit
FROM measurements
ORDER BY unit;

SELECT name,
       COALESCE(location, 'unknown') AS location
FROM devices;

