BEGIN TRY
    BEGIN TRANSACTION;

    UPDATE dbo.Devices
    SET Enabled = 0
    WHERE Id = @Id;

    COMMIT TRANSACTION;
END TRY
BEGIN CATCH
    IF @@TRANCOUNT > 0
        ROLLBACK TRANSACTION;

    THROW;
END CATCH;

CREATE TABLE #RecentMeasurements (
    DeviceId BIGINT NOT NULL,
    Value FLOAT NOT NULL
);

INSERT INTO #RecentMeasurements(DeviceId, Value)
SELECT DeviceId, Value
FROM dbo.Measurements
WHERE MeasuredAt >= @StartTime;

CREATE OR ALTER PROCEDURE dbo.DisableDevice
    @DeviceId BIGINT
AS
BEGIN
    SET NOCOUNT ON;

    UPDATE dbo.Devices
    SET Enabled = 0
    WHERE Id = @DeviceId;
END;

