const session = db.getMongo().startSession();
const app = session.getDatabase('app');

session.startTransaction();
try {
  app.devices.updateOne(
    { _id: deviceId },
    { $set: { enabled: false } }
  );

  app.audit.insertOne({
    deviceId,
    action: 'disable',
    createdAt: new Date()
  });

  session.commitTransaction();
} catch (error) {
  session.abortTransaction();
  throw error;
} finally {
  session.endSession();
}
